mapper.update:
UPDATE DMS_FOLDER
SET FOLDER_NM = #{folderNm}, UPD_ID = #{updId}, UPD_DT = NOW()
WHERE FAMILY_ID = #{familyId} AND FOLDER_SEQ = #{folderSeq}

mapper.select:
WITH RECURSIVE sub AS (
    SELECT FOLDER_SEQ FROM DMS_FOLDER
    WHERE FAMILY_ID = #{familyId} AND FOLDER_SEQ = #{folderSeq}
    UNION ALL
    SELECT f.FOLDER_SEQ FROM DMS_FOLDER f
    INNER JOIN sub s ON f.PARENT_SEQ = s.FOLDER_SEQ AND f.FAMILY_ID = #{familyId}
)
SELECT FOLDER_SEQ FROM sub

